1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const CURSED_SURCHARGE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_BASE = 60;
22	const BLOCK_SIZE = 3;
23	
24	function withFirstInsurance(base: number): number {
25	  return base + base * FIRST_INSURANCE_SURCHARGE;
26	}
27	
28	function itemBase(item: Item): number {
29	  return BASE_PREMIUMS[item.type];
30	}
31	
32	function groupByType(items: Item[]): Map<string, Item[]> {
33	  const groups = new Map<string, Item[]>();
34	  for (const item of items) {
35	    const list = groups.get(item.type) ?? [];
36	    list.push(item);
37	    groups.set(item.type, list);
38	  }
39	  return groups;
40	}
41	
42	function componentGroupBase(group: Item[]): number {
43	  const blocks = Math.floor(group.length / BLOCK_SIZE);
44	  const remainder = group.length - blocks * BLOCK_SIZE;
45	  return blocks * BLOCK_BASE + remainder * itemBase(group[0]);
46	}
47	
48	function componentsTotal(items: Item[]): number {
49	  let total = 0;
50	  for (const [, group] of groupByType(items)) {
51	    total += withFirstInsurance(componentGroupBase(group));
52	  }
53	  return total;
54	}
55	
56	function surchargeWhen(condition: boolean, base: number, rate: number): number {
57	  return condition ? base * rate : 0;
58	}
59	
60	function itemPremium(item: Item): number {
61	  const base = itemBase(item);
62	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
63	  const curseSurcharge = surchargeWhen(item.cursed === true, base, CURSED_SURCHARGE);
64	  const enchantmentSurcharge = surchargeWhen(isHighlyEnchanted, base, HIGH_ENCHANTMENT_SURCHARGE);
65	  return withFirstInsurance(base) + curseSurcharge + enchantmentSurcharge;
66	}
67	
68	function quotePremium(items: Item[]): number {
69	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
70	  const others = items.filter((item) => !COMPONENT_TYPES.has(item.type));
71	  const othersTotal = others.reduce(
72	    (sum, item) => sum + itemPremium(item),
73	    0,
74	  );
75	  return Math.ceil(othersTotal + componentsTotal(components) + PROCESSING_FEE);
76	}
77	
78	export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
79	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
80	  return { results };
81	}
